class Solution {
public:
    int minSteps(int n) {
        if (n == 1) return 0;
        int res = 0;
        int curr = 1, clip = 0;
        while (curr < n) {
            if (n % curr == 0) {
                res += 1;
                clip = curr;
            }
            curr += clip;
            res += 1;
        }
        return res;
    }
};
